mapper.select:
SELECT *
FROM im_sync_session
WHERE user_id = #{userId}
  AND device_id = #{deviceId}
  AND sync_status IN (1, 2) -- 进行中或已推送MQ
ORDER BY create_time DESC

mapper.update:
UPDATE im_sync_session
SET sync_status = #{syncStatus},
    error_message = #{errorMessage},
    update_time = #{updateTime}
WHERE sync_id = #{syncId}

UPDATE im_sync_session
SET sync_status = #{syncStatus},
    end_time = #{endTime},
    update_time = #{updateTime},
    last_activity_time = #{updateTime}
WHERE sync_id = #{syncId}

mapper.select:
SELECT *
FROM im_sync_session
WHERE sync_status IN (1, 2) -- 进行中或已推送MQ
  AND last_activity_time < #{expireTime}
  AND create_time < #{expireTime}

